  -- SOP 1: Audiovisual — Captação de Drone (Checklist Regulatório e Técnico)
  -- ══════════════════════════════════════════════════════════════════════════
  INSERT INTO knowledge_sops (
    tenant_id, title, slug, bu, category, description, content, content_html,
    status, priority, tags, order_index, version
  ) VALUES (
    v_tenant_id,
    'Captação de Drone — Checklist Regulatório e Técnico',
    'tbo-av-010-captacao-drone-checklist',
    'audiovisual',
    'checklist',
    'Processo completo para operações de drone em projetos imobiliários: homologação ANAC, autorizações, checklist técnico de voo e protocolos de segurança.',
    E'## Captação de Drone — Checklist Regulatório e Técnico\n\n### 1. Objetivo\nGarantir que toda operação de drone realizada pela TBO esteja em conformidade com a regulamentação ANAC (RBAC-E94), devidamente autorizada para o espaço aéreo, e executada com padrões técnicos que resultem em material de qualidade cinematográfica para projetos imobiliários. Zero voos não autorizados. Zero incidentes por falha de checklist.\n\n### 2. Escopo\n**Quem executa:** Piloto de drone certificado (ANAC) + Diretor de Fotografia/AV\n**Quando se aplica:** Qualquer captação aérea em projetos residenciais, terrenos, vizinhança e eventos de lançamento\n**Limites:** Não cobre edição/pós-produção (ver SOP tbo-av-009); não cobre drone indoor em maquetes/stands (protocolo diferente)\n\n### 3. RACI\n\n| Atividade | Responsável | Aprovador | Consultado | Informado |\n|---|---|---|---|---|\n| Análise de espaço aéreo e restrições | Piloto ANAC | Líder AV | — | Diretor Criativo |\n| Solicitação de autorização DECEA/ANAC | Piloto ANAC | Líder AV | Jurídico (se necessário) | Atendimento |\n| Checklist pré-voo técnico | Piloto ANAC | — | — | Líder AV |\n| Direção de captação (ângulos, rotas) | Dir. Fotografia | Marco (Dir. Criativo) | Cliente | Piloto |\n| Aprovação do material bruto | Líder AV | Marco | Cliente | — |\n| Arquivamento e entrega | Assistente AV | Líder AV | — | Atendimento |\n\n### 4. Pré-requisitos\n\n**Regulatórios (obrigatórios antes de qualquer voo):**\n- [ ] Piloto com certificado ANAC vigente (BVLOS ou VLOS conforme operação)\n- [ ] Drone cadastrado no SISANT (Sistema de Aeronaves Não Tripuladas)\n- [ ] Seguro de responsabilidade civil aeronáutica ativo\n- [ ] Consulta ao mapa de espaço aéreo (DECEA — aplicativo iSAGA ou SARPAS)\n- [ ] Autorização DECEA emitida (para áreas controladas — prazo mínimo 3 dias úteis)\n- [ ] Comunicado à Prefeitura local (se área urbana com restrição municipal)\n\n**Técnicos:**\n- [ ] Briefing criativo aprovado (ângulos, rotas, hora do dia, mood)\n- [ ] Baterias completamente carregadas (mínimo 3 baterias para diária completa)\n- [ ] Drone calibrado e firmware atualizado\n- [ ] Cartão de memória formatado (mínimo 128GB disponível)\n- [ ] Previsão meteorológica verificada (vento < 8 m/s, sem chuva, visibilidade > 1km)\n\n### 5. Procedimento\n\n**5.1 Planejamento (D-5 até D-3)**\n1. Receber briefing de captação: endereço exato, ângulos desejados, horário solar (golden hour vs. dia aberto)\n2. Acessar iSAGA/SARPAS e verificar:\n   - Classe do espaço aéreo (G = livre; E/D/C/B = autorização obrigatória)\n   - TMA (Área de Controle Terminal) — verificar distância de aeroportos\n   - Restrições de altura (padrão urbano: máx. 120m AGL)\n   - Áreas proibidas (bases militares, centrais nucleares, raio de 1km de helipontos)\n3. Solicitar autorização DECEA via SARPAS com mínimo 3 dias úteis de antecedência\n4. Aguardar N-autorização com número de protocolo\n5. Planejar rota de voo: pontos de interesse, altitude por ponto, velocidade\n6. Verificar previsão do tempo para o dia e dia seguinte (backup)\n\n**5.2 Preparação no dia (D-day, 1h antes do voo)**\n1. Verificar autorização DECEA válida para o horário e local exatos\n2. Checklist de equipamento (ver Template Checklist Pré-Voo abaixo)\n3. Checar bateria do controle remoto (100%)\n4. Calibrar bússola no local (longe de metal e cabos elétricos)\n5. Definir ponto de pouso seguro e zona de segurança (raio mínimo 30m)\n6. Informar equipe presente sobre área restrita durante o voo\n7. Avisar Bombeiros/Samu do voo (recomendado em áreas urbanas densas)\n\n**5.3 Execução do Voo**\n1. Decolar no modo Manual ou Sport (evitar Auto para primeira verificação do local)\n2. Testar comunicação controle-drone em 10m de altitude antes de subir\n3. Executar plano de voo: golden hour shots primeiro (luz muda rápido)\n4. Filmar cada ponto com RAW + H.265 em resolução máxima (4K/5.1K)\n5. Capturas obrigatórias para projeto imobiliário:\n   - Órbita do terreno/edificação (360° a 3 distâncias: 50m, 100m, 150m)\n   - Fly-through de acesso (rua de entrada → fachada)\n   - Ponto zenital do terreno/empreendimento\n   - Contexto urbano (vizinhança, comércio, acessos)\n   - Golden shot: ângulo mais favorável com luz ideal\n6. Monitorar bateria constantemente: RTH (Return to Home) automático em 20%\n7. Aterrissar com mínimo 15% de bateria restante\n\n**5.4 Pós-Voo (no local)**\n1. Backup imediato no HD externo (não sair do local sem backup)\n2. Verificar material no monitor: foco, exposição, horizonte, shake\n3. Se material com problema: re-voo imediato se bateria e autorização permitirem\n4. Registrar log de voo: horário, local, altitude máxima, baterias usadas\n\n**5.5 Pós-Voo (escritório)**\n1. Transferir material para servidor TBO em pasta estruturada: `PROJETO/AV/DRONE/BRUTO/`\n2. Selecionar takes aprovados e transferir para: `PROJETO/AV/DRONE/APROVADOS/`\n3. Arquivar autorização DECEA digitalizada em: `PROJETO/AV/DRONE/DOCUMENTOS/`\n4. Passar material aprovado para editor AV com briefing de pós-produção\n\n### 6. Checklist de Validação\n\n**Regulatório:**\n- [ ] Autorização DECEA válida arquivada no projeto\n- [ ] Drone cadastrado SISANT (número de série na autorização)\n- [ ] Piloto certificado (número ANAC registrado no log)\n- [ ] Seguro vigente (número da apólice no log)\n\n**Técnico:**\n- [ ] Material em 4K/5.1K RAW ou Log\n- [ ] Todos os ângulos do briefing captados\n- [ ] Backup em HD externo realizado no local\n- [ ] Log de voo preenchido e arquivado\n- [ ] Material transferido para servidor (não apenas HD externo)\n\n**Qualidade:**\n- [ ] Horizonte nivelado em todos os planos (tolerância ±1°)\n- [ ] Sem shake ou vibração visível\n- [ ] Exposição correta (histograma sem clipping)\n- [ ] Todos os ângulos obrigatórios presentes\n\n### 7. Ferramentas e Recursos\n\n**Softwares regulatórios:**\n- iSAGA (app DECEA — mapa de espaço aéreo): decea.gov.br\n- SARPAS (autorização online): decea.gov.br/sarpas\n- AirMap: consulta de espaço aéreo em tempo real\n\n**Hardware padrão TBO:**\n- DJI Mavic 3 Pro (principal) / DJI Air 3 (backup/mobilidade)\n- Filtros ND (4, 8, 16, 64) para controle de exposição\n- HD externo SSD 2TB para backup em campo\n- Monitor externo 7\" para verificação de material\n\n**Templates:**\n- Log de voo padrão TBO (ver Template Anexo)\n- Pasta de projeto padrão (estrutura de arquivos AV)\n\n### 8. SLAs e Métricas\n\n| Etapa | SLA |\n|---|---|\n| Solicitação DECEA | D-3 úteis (mínimo) antes do voo |\n| Briefing para piloto | D-2 antes do voo |\n| Backup em campo | 30 min após pouso |\n| Transferência para servidor | Mesmo dia do voo |\n| Seleção de takes aprovados | D+1 após captação |\n\n**KPIs de qualidade:**\n- Taxa de aprovação de material: >85% dos takes captados aprovados\n- Zero incidentes regulatórios\n- Zero re-produções por falha técnica (foco, exposição, shake)\n\n### 9. Troubleshooting\n\n**Autorização DECEA negada:**\n→ Verificar se o local está em área de exclusão permanente (bases militares, etc.)\n→ Se área controlada temporária (NOTAM), aguardar expiração ou renegociar data de captação\n→ Contatar DECEA para recurso (prazo adicional 5 dias úteis)\n\n**Drone com problema técnico no local:**\n→ Não voar! Acionar backup (DJI Air 3) ou reagendar\n→ Registrar problema para manutenção preventiva\n→ Se agendamento urgente, verificar locação de drone certificado\n\n**Material com defeito descoberto na pós:**\n→ Verificar se autorização DECEA ainda é válida para re-captação\n→ Se expirada: nova solicitação SARPAS (3 dias úteis)\n→ Negociar re-captação com cliente: comunicar antes de entregar material ruim\n\n**Condição meteorológica adversa no dia:**\n→ Cancelar voo se vento > 8 m/s, chuva, ou visibilidade < 1km\n→ Protocolo: avisar cliente com 3h de antecedência, propor nova data\n→ Não há reembolso de diária cancelada por condição climática (incluir em contrato)\n\n### 10. Template Anexo\n\n```markdown\n# LOG DE VOO — TBO Audiovisual\n\n## Identificação\n- **Projeto:** ___________________________\n- **Data:** ___________________________\n- **Local:** ___________________________\n- **Piloto:** ___________________________ (N° ANAC: _______)\n- **Drone:** ___________________________ (N° SISANT: _______)\n\n## Autorização Regulatória\n- **N° Autorização DECEA:** ___________________________\n- **Validade da autorização:** _______________ até _______________\n- **Classe espaço aéreo:** [ ] G [ ] E [ ] D [ ] C [ ] B\n- **Altura máxima autorizada:** _______ metros AGL\n- **Seguro apólice N°:** ___________________________\n\n## Condições Meteorológicas\n- **Horário do voo:** _______________ até _______________\n- **Temperatura:** _______ °C\n- **Vento:** _______ m/s / direção: _______\n- **Visibilidade:** _______\n- **Condição geral:** [ ] Excelente [ ] Boa [ ] Aceitável [ ] Ruim (não voou)\n\n## Baterias Utilizadas\n| Bateria | Carga inicial | Carga final | Ciclos |\n|---------|---------------|-------------|--------|\n| 01 | % | % | |\n| 02 | % | % | |\n| 03 | % | % | |\n\n## Capturas Realizadas\n- [ ] Órbita 50m\n- [ ] Órbita 100m\n- [ ] Órbita 150m\n- [ ] Fly-through acesso\n- [ ] Ponto zenital\n- [ ] Contexto urbano\n- [ ] Golden shot\n- Outros: ___________________________\n\n## Material\n- **Resolução:** [ ] 4K [ ] 5.1K [ ] Outro: _______\n- **Codec:** [ ] H.265 RAW [ ] H.264 [ ] Log (perfil: _______)\n- **Total de arquivos:** _______\n- **Tamanho total:** _______ GB\n- **Backup realizado em campo:** [ ] Sim [ ] Não\n- **HD externo ID:** ___________________________\n\n## Ocorrências\n___________________________\n\n## Assinatura\n**Piloto:** ___________________________ Data: _______________\n```',
    '',
    'published',
    'critical',
    ARRAY['drone', 'ANAC', 'DECEA', 'captação aérea', 'audiovisual', 'regulatório', 'checklist', 'imobiliário'],
    10,
    1
  ) ON CONFLICT (tenant_id, slug) DO UPDATE SET
    title = EXCLUDED.title,
    content = EXCLUDED.content,
    priority = EXCLUDED.priority,
    tags = EXCLUDED.tags,
    version = knowledge_sops.version + 1;

  SELECT id INTO v_sop_id FROM knowledge_sops WHERE tenant_id = v_tenant_id AND slug = 'tbo-av-010-captacao-drone-checklist';

  INSERT INTO knowledge_sop_steps (sop_id, step_number, title, content, step_type, order_index)
  VALUES
    (v_sop_id, 1, 'Objetivo', 'Garantir conformidade ANAC/DECEA e execução técnica de alta qualidade em toda captação aérea de drone para projetos imobiliários. Zero voos não autorizados. Zero incidentes por falha de checklist.', 'step', 0),
    (v_sop_id, 2, 'Escopo', 'Quem executa: Piloto certificado ANAC + Diretor de Fotografia. Aplica-se a qualquer captação aérea em projetos residenciais, terrenos, vizinhança ou eventos de lançamento. Não cobre drone indoor.', 'step', 1),
    (v_sop_id, 3, 'RACI', '| Atividade | Responsável | Aprovador | Consultado | Informado |
|---|---|---|---|---|
| Análise espaço aéreo | Piloto ANAC | Líder AV | — | Dir. Criativo |
| Autorização DECEA | Piloto ANAC | Líder AV | Jurídico | Atendimento |
| Checklist pré-voo | Piloto ANAC | — | — | Líder AV |
| Direção de captação | Dir. Fotografia | Marco | Cliente | Piloto |
| Aprovação material | Líder AV | Marco | Cliente | — |', 'step', 2),
    (v_sop_id, 4, 'Pré-requisitos', E'**Regulatórios (obrigatórios):**\n- Piloto com certificado ANAC vigente\n- Drone cadastrado no SISANT\n- Seguro de responsabilidade civil aeronáutica ativo\n- Consulta ao mapa de espaço aéreo (iSAGA/SARPAS)\n- Autorização DECEA emitida (prazo mínimo 3 dias úteis)\n\n**Técnicos:**\n- Briefing criativo aprovado\n- 3 baterias 100% carregadas\n- Drone calibrado e firmware atualizado\n- Previsão meteorológica: vento < 8 m/s, sem chuva', 'step', 3),
    (v_sop_id, 5, 'Procedimento', E'**D-5 a D-3:** Análise de espaço aéreo → Solicitação DECEA via SARPAS → Planejamento de rota\n**D-day, 1h antes:** Checklist de equipamento → Calibração bússola → Definir zona de segurança\n**Execução:** Decolar → Testar comunicação → Capturas obrigatórias (órbita 3 distâncias, fly-through, zenital, contexto, golden shot)\n**Pós-voo campo:** Backup imediato HD externo → Verificar material → Log de voo\n**Pós-voo escritório:** Transferir para servidor → Selecionar aprovados → Passar para editor', 'step', 4),
    (v_sop_id, 6, 'Checklist de Validação', E'**Regulatório:**\n- [ ] Autorização DECEA válida arquivada\n- [ ] Drone cadastrado SISANT\n- [ ] Piloto certificado (N° ANAC no log)\n- [ ] Seguro vigente no log\n\n**Técnico:**\n- [ ] Material em 4K/5.1K RAW ou Log\n- [ ] Todos os ângulos do briefing captados\n- [ ] Backup em HD externo realizado no local\n- [ ] Log de voo preenchido e arquivado\n\n**Qualidade:**\n- [ ] Horizonte nivelado (tolerância ±1°)\n- [ ] Sem shake ou vibração\n- [ ] Exposição correta (sem clipping)', 'checkpoint', 5),
    (v_sop_id, 7, 'Ferramentas e Recursos', E'- **iSAGA** (app DECEA — mapa espaço aéreo): decea.gov.br\n- **SARPAS** (autorização online)\n- **AirMap** — consulta espaço aéreo em tempo real\n- **Hardware:** DJI Mavic 3 Pro (principal), DJI Air 3 (backup)\n- **Filtros ND** 4/8/16/64 para controle de exposição\n- **HD SSD 2TB** para backup em campo\n- Log de voo padrão TBO (Template Anexo)', 'tip', 6),
    (v_sop_id, 8, 'SLAs e Métricas', E'| Etapa | SLA |\n|---|---|\n| Solicitação DECEA | D-3 úteis |\n| Briefing para piloto | D-2 |\n| Backup em campo | 30 min após pouso |\n| Transferência servidor | Mesmo dia |\n| Seleção de takes | D+1 |\n\n**KPIs:** Taxa de aprovação >85% · Zero incidentes regulatórios · Zero re-produções por falha técnica', 'note', 7),
    (v_sop_id, 9, 'Troubleshooting', E'**DECEA negada:** Verificar área de exclusão permanente ou NOTAM temporário. Aguardar ou renegociar data.\n**Problema técnico no local:** Não voar. Usar backup (Air 3) ou reagendar. Registrar para manutenção.\n**Material com defeito na pós:** Verificar validade da autorização. Se expirada, nova solicitação (3 dias). Comunicar cliente antes de entregar material ruim.\n**Meteorologia adversa:** Cancelar se vento > 8 m/s ou chuva. Avisar cliente com 3h de antecedência.', 'warning', 8),
    (v_sop_id, 10, 'Template Anexo', E'**Log de Voo TBO** — Template copy-paste disponível no conteúdo completo deste SOP.\n\nCampos: Identificação do projeto e piloto · Autorização DECEA e validade · Condições meteorológicas · Registro de baterias · Capturas realizadas · Dados do material · Ocorrências · Assinatura do piloto', 'tip', 9);


  -- ══════════════════════════════════════════════════════════════════════════
  -- SOP 2: Digital 3D — Entrega Final de Assets ao Cliente
  -- ══════════════════════════════════════════════════════════════════════════
  INSERT INTO knowledge_sops (
    tenant_id, title, slug, bu, category, description, content, content_html,
    status, priority, tags, order_index, version
  ) VALUES (
    v_tenant_id,
    'Entrega Final de Assets ao Cliente — Digital 3D',
    'tbo-d3d-009-entrega-final-assets-cliente',
    'digital-3d',
    'processo',
    'Processo de organização, nomenclatura, empacotamento e entrega dos arquivos finais de renders, animações e assets 3D ao cliente, garantindo rastreabilidade e padrão de qualidade TBO.',
    E'## Entrega Final de Assets ao Cliente — Digital 3D\n\n### 1. Objetivo\nPadronizar o processo de empacotamento e entrega dos arquivos finais de renders, animações e assets 3D ao cliente, garantindo que a entrega seja completa, organizada, nomenclada corretamente e documentada — eliminando retrabalho por arquivos faltantes, formatos errados ou resolução inadequada. A entrega final é o cartão de visitas do trabalho técnico da TBO.\n\n### 2. Escopo\n**Quem executa:** Líder de D3D + Artista 3D responsável pelo projeto\n**Quando se aplica:** Ao término de cada etapa de entrega (parcial ou final) de renders, animações 3D, tours virtuais ou assets avulsos para cliente externo\n**Limites:** Não cobre entrega de arquivos fonte editáveis (arquivos .blend, .max, .c4d) — requer autorização contratual específica; não cobre entrega de peças gráficas finalizadas (responsabilidade do Design)\n\n### 3. RACI\n\n| Atividade | Responsável | Aprovador | Consultado | Informado |\n|---|---|---|---|---|\n| Organização e nomenclatura de arquivos | Artista 3D | Líder D3D | — | — |\n| QC final (qualidade, resolução, formatos) | Líder D3D | Marco (Dir. Criativo) | — | Atendimento |\n| Upload e geração de link de entrega | Artista 3D | Líder D3D | — | Atendimento |\n| Envio ao cliente com briefing de uso | Atendimento | Ruy (Dir. Comercial) | — | Cliente |\n| Arquivamento interno | Artista 3D | Líder D3D | — | — |\n\n### 4. Pré-requisitos\n- [ ] Aprovação formal do cliente na última rodada de revisão (e-mail ou mensagem registrada no TBO OS)\n- [ ] QC de renders concluído (checklist SOP tbo-d3d-008 executado)\n- [ ] Versão final dos arquivos isolados da versão de trabalho\n- [ ] Briefing de entrega definido: quais formatos, resoluções e variações o cliente precisa\n- [ ] Acesso ao Google Drive do projeto ativo e com espaço disponível\n\n### 5. Procedimento\n\n**5.1 Organização de Arquivos**\n\nEstrutura obrigatória de pastas:\n```\n[CODIGO-PROJETO]_[NOME-EMPREENDIMENTO]_ENTREGA_[VERSAO]/\n├── RENDERS/\n│   ├── EXTERNAS/\n│   ├── INTERNAS/\n│   ├── AEREA/\n│   └── AMBIENTACAO/\n├── ANIMACOES/\n│   ├── PROXYS/        ← versão web (720p/1080p)\n│   └── MASTERS/       ← versão master (4K+ sem compressão)\n├── TOUR_VIRTUAL/      ← se aplicável\n├── VARIANTES/         ← opções de acabamento, paletas, etc.\n└── DOCUMENTOS/\n    ├── RELATORIO_ENTREGA.pdf\n    └── TERMOS_DE_USO.pdf\n```\n\n**5.2 Nomenclatura de Arquivos**\n\nPadrão obrigatório:\n```\n[PROJETO]_[TIPO]_[AMBIENTE]_[VARIANTE]_[VERSAO].[EXT]\n\nExemplos:\nVST001_EXT_FACHADA_PRINCIPAL_v01.jpg\nVST001_INT_SALA_OPCAO-A_v01.jpg\nVST001_AER_CONTEXTO_DIURNO_v01.jpg\nVST001_ANI_FLYTHROUGH_ENTRADA_v01.mp4\n```\n\nRegras:\n- NUNCA usar espaços, acentos ou caracteres especiais\n- Sempre incluir número de versão (_v01, _v02)\n- Letras maiúsculas para código do projeto e tipo\n- Tipos: EXT (externa), INT (interna), AER (aérea), AMB (ambientação), ANI (animação), TUR (tour)\n\n**5.3 Formatos e Resoluções Obrigatórios**\n\n| Tipo | Formato Master | Formato Web | Resolução mínima |\n|---|---|---|---|\n| Renders externos | TIFF 16bit | JPG 95% | 4000px lado maior |\n| Renders internos | TIFF 16bit | JPG 95% | 3500px lado maior |\n| Renders aéreos | TIFF 16bit | JPG 95% | 5000px lado maior |\n| Animações | ProRes 4444 | H.264 1080p | 3840×2160 (master) |\n| Tour virtual | Formato nativo | Link hosted | — |\n\nSalvo instrução contrária do cliente em briefing, SEMPRE entregar ambos (master + web).\n\n**5.4 Checklist QC Final**\nExecutar antes de compactar para entrega:\n1. Abrir cada render em 100% zoom — verificar foco, artefatos, aliasing\n2. Verificar nomenclatura de TODOS os arquivos (sem exceção)\n3. Confirmar resolução de cada arquivo vs. briefing\n4. Verificar que pasta VARIANTES está completa (todas as opções aprovadas)\n5. Testar link de tour virtual em 3 dispositivos (desktop, tablet, celular) se aplicável\n6. Gerar MD5/SHA256 de verificação para arquivos críticos (animações master)\n\n**5.5 Relatório de Entrega**\n\nGerar PDF com:\n- Lista de todos os arquivos entregues (nome, formato, resolução, tamanho)\n- Data de aprovação da versão final\n- Termos de uso e licença dos assets\n- Contato TBO para suporte pós-entrega (30 dias)\n- Instruções de uso recomendadas (resolução para impressão, web, etc.)\n\n**5.6 Upload e Link de Entrega**\n1. Compactar pasta de entrega em ZIP (evitar RAR — compatibilidade)\n2. Fazer upload no Google Drive do projeto: `[PROJETO]/ENTREGAS/[DATA]/`\n3. Gerar link compartilhável com prazo de 30 dias\n4. Testar o link antes de enviar ao cliente\n5. Comunicar ao Atendimento: link + relatório de entrega + prazo de expiração\n\n**5.7 Arquivamento Interno**\n1. Manter cópia de segurança em HD externo TBO (NAS ou similar)\n2. Arquivar na estrutura interna: `PROJETOS/[ANO]/[PROJETO]/FINAL_ENTREGUE/`\n3. Registrar entrega no TBO OS (data, versão, link, quem aprovou)\n\n### 6. Checklist de Validação\n\n- [ ] Estrutura de pastas conforme padrão\n- [ ] TODOS os arquivos com nomenclatura correta (zero espaços/acentos)\n- [ ] Formatos master E web presentes para renders\n- [ ] Resoluções mínimas atendidas para todos os arquivos\n- [ ] QC visual executado em 100% zoom\n- [ ] Relatório de entrega gerado em PDF\n- [ ] Link de entrega testado antes de enviar ao cliente\n- [ ] Cópia arquivada internamente (HD + TBO OS)\n- [ ] Entrega registrada no TBO OS com data e aprovador\n\n### 7. Ferramentas e Recursos\n\n- **Google Drive** — repositório de entrega ao cliente\n- **Adobe Bridge / File Explorer** — organização e renomeação em lote\n- **HandBrake** — transcodificação de vídeos para proxy web\n- **Bulk Rename Utility** — renomeação em lote conforme padrão\n- **PDF24 / Adobe Acrobat** — geração do relatório de entrega\n- **TBO OS** — registro formal da entrega\n- Template de Relatório de Entrega (ver Template Anexo)\n\n### 8. SLAs e Métricas\n\n| Etapa | SLA |\n|---|---|\n| Organização e nomenclatura | D+0 após aprovação final |\n| QC final | D+1 |\n| Upload e geração de link | D+1 |\n| Envio ao cliente | D+2 (máx.) após aprovação final |\n| Prazo do link de entrega | 30 dias |\n\n**KPIs:**\n- Zero arquivos com nomenclatura incorreta na entrega final\n- Zero re-entregas por formato/resolução errado\n- Taxa de satisfação pós-entrega: >90% (pesquisa NPS)\n\n### 9. Troubleshooting\n\n**Cliente solicita formato não previsto no briefing:**\n→ Verificar se o arquivo master permite conversão sem perda\n→ Se sim: converter e incluir na entrega sem custo adicional\n→ Se não (ex.: vetor a partir de render): cobrar hora extra e alinhar prazo\n\n**Arquivo corrompido detectado no QC:**\n→ Identificar se é problema de export ou de arquivo fonte\n→ Re-exportar a partir do arquivo 3D aprovado\n→ Nunca entregar arquivo com problema — comunicar atraso ao Atendimento com nova data\n\n**Link de entrega expirado (cliente perdeu prazo):**\n→ Reativar link por mais 15 dias (uma vez, sem custo)\n→ A partir da segunda reativação: cobrar taxa de manutenção de arquivo\n→ Incluir essa política no contrato e no relatório de entrega\n\n**Tamanho total excede capacidade do Drive:**\n→ Separar em múltiplos zips (<4GB cada) ou usar WeTransfer Pro\n→ Para projetos >50GB: usar link de pasta diretamente (sem ZIP)\n\n### 10. Template Anexo\n\n```markdown\n# RELATÓRIO DE ENTREGA — TBO Digital 3D\n\n**Projeto:** ___________________________\n**Empreendimento:** ___________________________\n**Cliente:** ___________________________\n**Data de entrega:** ___________________________\n**Versão:** ___________________________ (aprovada em: _______________)\n**Responsável TBO:** ___________________________\n\n## Arquivos Entregues\n\n| # | Nome do arquivo | Formato | Resolução | Tamanho |\n|---|---|---|---|---|\n| 1 | | | | |\n| 2 | | | | |\n| 3 | | | | |\n\n**Total de arquivos:** _______\n**Tamanho total:** _______ GB\n\n## Link de Entrega\n- **URL:** ___________________________\n- **Validade:** _______________ (30 dias a partir da entrega)\n- **Senha (se aplicável):** ___________________________\n\n## Termos de Uso\nOs assets entregues são licenciados para uso exclusivo do empreendimento [NOME] para fins de marketing, vendas e comunicação. É vedada a utilização em outros empreendimentos sem autorização prévia da TBO. Modificações nos arquivos por terceiros sem anuência da TBO isentam a agência de responsabilidade sobre o resultado final.\n\n## Suporte Pós-Entrega\nA TBO oferece suporte técnico por 30 dias após a entrega para esclarecimento de dúvidas sobre os arquivos entregues.\n- **Contato:** projetos@agenciatbo.com.br\n- **WhatsApp:** ___________________________\n\n---\n*Entrega realizada pela TBO — Agência de Branding e Visualização*\n```',
    '',
    'published',
    'high',
    ARRAY['entrega', 'assets', 'renders', 'nomenclatura', 'digital 3D', 'qualidade', 'cliente', 'arquivamento'],
    9,
    1
  ) ON CONFLICT (tenant_id, slug) DO UPDATE SET
    title = EXCLUDED.title,
    content = EXCLUDED.content,
    priority = EXCLUDED.priority,
    tags = EXCLUDED.tags,
