  SELECT id INTO v_sop_id FROM knowledge_sops WHERE tenant_id = v_tenant_id AND slug = 'tbo-d3d-009-entrega-final-assets-cliente';

  INSERT INTO knowledge_sop_steps (sop_id, step_number, title, content, step_type, order_index)
  VALUES
    (v_sop_id, 1, 'Objetivo', 'Padronizar o empacotamento e entrega dos arquivos finais de renders, animações e assets 3D ao cliente, garantindo completude, nomenclatura correta e documentação — eliminando retrabalho por arquivos faltantes ou formatos errados.', 'step', 0),
    (v_sop_id, 2, 'Escopo', 'Quem executa: Líder de D3D + Artista 3D responsável. Aplica-se a todas as entregas (parciais ou finais) de renders, animações 3D, tours virtuais ou assets avulsos para clientes externos. Não cobre arquivos fonte editáveis sem autorização contratual.', 'step', 1),
    (v_sop_id, 3, 'RACI', E'| Atividade | Responsável | Aprovador | Consultado | Informado |\n|---|---|---|---|---|\n| Organização e nomenclatura | Artista 3D | Líder D3D | — | — |\n| QC final | Líder D3D | Marco | — | Atendimento |\n| Upload e link de entrega | Artista 3D | Líder D3D | — | Atendimento |\n| Envio ao cliente | Atendimento | Ruy | — | Cliente |\n| Arquivamento interno | Artista 3D | Líder D3D | — | — |', 'step', 2),
    (v_sop_id, 4, 'Pré-requisitos', E'- Aprovação formal do cliente na última revisão (registrada no TBO OS)\n- QC de renders concluído (SOP tbo-d3d-008 executado)\n- Versão final isolada da versão de trabalho\n- Briefing de entrega definido: formatos, resoluções, variações\n- Google Drive do projeto com espaço disponível', 'step', 3),
    (v_sop_id, 5, 'Procedimento', E'1. **Organizar pastas** conforme estrutura padrão TBO (RENDERS/EXTERNAS, INTERNAS, AEREA; ANIMACOES/PROXYS, MASTERS; DOCUMENTOS)\n2. **Nomenclar arquivos** seguindo padrão: [PROJETO]_[TIPO]_[AMBIENTE]_[VARIANTE]_[VERSAO].[EXT] — sem espaços/acentos\n3. **Exportar formatos**: renders em TIFF master + JPG web; animações em ProRes 4444 + H.264 1080p\n4. **QC visual** 100% zoom em todos os arquivos\n5. **Gerar Relatório de Entrega** em PDF (lista de arquivos, termos de uso, contato suporte)\n6. **Upload no Google Drive** + geração de link com prazo 30 dias\n7. **Testar link** antes de enviar\n8. **Comunicar Atendimento** com link + relatório\n9. **Arquivar internamente** (HD + TBO OS)', 'step', 4),
    (v_sop_id, 6, 'Checklist de Validação', E'- [ ] Estrutura de pastas conforme padrão\n- [ ] Todos os arquivos com nomenclatura correta\n- [ ] Formatos master E web presentes para renders\n- [ ] Resoluções mínimas atendidas (4000px renders ext, 5000px aéreo)\n- [ ] QC visual em 100% zoom executado\n- [ ] Relatório de entrega gerado em PDF\n- [ ] Link de entrega testado\n- [ ] Cópia arquivada internamente (HD + TBO OS)\n- [ ] Registro de entrega no TBO OS', 'checkpoint', 5),
    (v_sop_id, 7, 'Ferramentas e Recursos', E'- Google Drive (repositório de entrega)\n- Bulk Rename Utility (renomeação em lote)\n- HandBrake (transcodificação vídeos web)\n- PDF24/Adobe Acrobat (relatório de entrega)\n- TBO OS (registro formal)\n- Template de Relatório de Entrega (ver conteúdo completo do SOP)', 'tip', 6),
    (v_sop_id, 8, 'SLAs e Métricas', E'| Etapa | SLA |\n|---|---|\n| Organização e nomenclatura | D+0 após aprovação |\n| QC final | D+1 |\n| Upload + link | D+1 |\n| Envio ao cliente | D+2 (máx.) |\n| Validade do link | 30 dias |\n\n**KPIs:** Zero arquivos com nomenclatura incorreta · Zero re-entregas por formato errado · NPS pós-entrega >90%', 'note', 7),
    (v_sop_id, 9, 'Troubleshooting', E'**Formato não previsto no briefing:** Verificar se master permite conversão. Se sim, converter sem custo. Se não, cobrar hora extra.\n**Arquivo corrompido no QC:** Re-exportar do 3D aprovado. Nunca entregar com problema — comunicar atraso ao Atendimento.\n**Link expirado (cliente perdeu prazo):** Reativar por 15 dias (uma vez sem custo). Segunda vez: cobrar taxa de manutenção.\n**Tamanho excede capacidade:** Separar em ZIPs <4GB ou usar pasta Drive sem compactação para projetos >50GB.', 'warning', 8),
    (v_sop_id, 10, 'Template Anexo', E'**Relatório de Entrega TBO Digital 3D** — Template copy-paste disponível no conteúdo completo deste SOP.\n\nIncluí: identificação do projeto e cliente, lista de arquivos com formato/resolução/tamanho, link de entrega com validade, termos de uso, informações de suporte pós-entrega 30 dias.', 'tip', 9);


  -- ══════════════════════════════════════════════════════════════════════════
  -- SOP 3: RH — Offboarding de Colaborador
  -- ══════════════════════════════════════════════════════════════════════════
  INSERT INTO knowledge_sops (
    tenant_id, title, slug, bu, category, description, content, content_html,
    status, priority, tags, order_index, version
  ) VALUES (
    v_tenant_id,
    'Offboarding de Colaborador',
    'tbo-rh-010-offboarding-colaborador',
    'recursos-humanos',
    'processo',
    'Processo estruturado de desligamento de colaboradores CLT e PJ, cobrindo aviso prévio, transferência de conhecimento, revogação de acessos, documentação e entrevista de saída.',
    E'## Offboarding de Colaborador\n\n### 1. Objetivo\nGarantir que o desligamento de qualquer colaborador (CLT ou PJ) seja conduzido com organização, segurança e respeito — preservando o conhecimento institucional, protegendo os ativos digitais da TBO, cumprindo obrigações legais e mantendo uma relação positiva com o profissional que está saindo. Um offboarding ruim custa mais do que um onboarding: destrói conhecimento, expõe a empresa e compromete a reputação como empregador.\n\n### 2. Escopo\n**Quem executa:** Head de RH + Líder direto do colaborador + Ruy (Diretor de Operações)\n**Quando se aplica:** Desligamento voluntário (pedido de demissão), involuntário (demissão sem justa causa ou com justa causa) ou encerramento de contrato PJ\n**Limites:** Não cobre desligamento por justa causa com implicações jurídicas graves — nesses casos, envolver advogado trabalhista antes de qualquer ação\n\n### 3. RACI\n\n| Atividade | Responsável | Aprovador | Consultado | Informado |\n|---|---|---|---|---|\n| Decisão de desligamento | Ruy / Marco | Marco / Ruy | Head RH | Líder direto |\n| Comunicação ao colaborador | Ruy | Marco | Head RH | Líder direto |\n| Documentação legal (CLT) | Head RH | Ruy | Contador/DP | Colaborador |\n| Revogação de acessos digitais | Head RH + TI | Ruy | Líder direto | — |\n| Transferência de conhecimento | Líder direto | Ruy | Colaborador | Equipe |\n| Devolução de equipamentos | Head RH | Líder direto | — | Colaborador |\n| Entrevista de saída | Head RH | — | Ruy (se pertinente) | — |\n| Comunicação interna | Ruy | Marco | Head RH | Toda equipe |\n\n### 4. Pré-requisitos\n- [ ] Decisão de desligamento formalizada e alinhada entre Marco e Ruy\n- [ ] Data de desligamento definida (respeitando aviso prévio se CLT)\n- [ ] Inventário de acessos digitais do colaborador levantado\n- [ ] Inventário de equipamentos TBO em posse do colaborador levantado\n- [ ] Lista de projetos ativos e responsabilidades em curso mapeada\n\n### 5. Procedimento\n\n**5.1 D-30 (ou data da decisão) — Planejamento**\n1. Ruy + Marco definem: tipo de desligamento, data efetiva, verbas rescisórias (CLT) ou prazo de encerramento (PJ)\n2. Head RH levanta:\n   - Projetos em andamento do colaborador\n   - Acessos digitais (e-mail, Google Drive, Slack, TBO OS, ferramentas pagas, redes sociais)\n   - Equipamentos TBO em posse\n   - Documentos que precisa devolver/assinar\n3. Definir plano de transição: quem absorve as responsabilidades\n\n**5.2 Comunicação ao Colaborador (Dia D)**\n1. Conversa conduzida por Ruy (ou Marco se for caso especial) + Head RH presente\n2. Tom: direto, respeitoso, sem rodeios\n3. Informar:\n   - Motivo do desligamento (quando aplicável e legal)\n   - Data efetiva de saída\n   - O que acontece com as pendências\n   - Próximos passos da documentação\n4. NÃO comunicar antes de ter tudo preparado (acessos, documentos, plano de transição)\n5. Registrar conversa em ata interna (sem assinar pelo colaborador — apenas registro interno)\n\n**5.3 Período de Transição (D até D-final)**\n\nSe houver período de aviso trabalhado:\n1. Colaborador executa transferência de conhecimento estruturada:\n   - Documentar processos que só ele sabia (Wiki/TBO OS)\n   - Passagem de projetos ativos (reunião com substituto + Líder)\n   - Atualização de documentações pendentes\n   - Entrega de senhas e credenciais (via Bitwarden compartilhado)\n2. Líder monitora e garante que a transferência ocorre de fato\n3. Head RH prepara documentação: TRCT (CLT), Distrato (PJ), Declaração de encerramento\n\n**5.4 Revogação de Acessos (no último dia ou imediatamente para desligamentos involuntários)**\n\nSequência obrigatória (não alterar a ordem):\n1. [ ] Transferir e-mails importantes para arquivo compartilhado antes de desativar\n2. [ ] Remover do Google Workspace (desativar conta — não deletar, manter em suspend por 90 dias)\n3. [ ] Revogar acesso ao TBO OS\n4. [ ] Remover do Slack (exportar histórico se necessário)\n5. [ ] Revogar acesso a ferramentas pagas: Figma, Adobe CC, Notion, Asana, etc.\n6. [ ] Revogar acesso a redes sociais da TBO / clientes\n7. [ ] Revogar acesso a repositórios (GitHub, Drive de clientes)\n8. [ ] Trocar senhas compartilhadas que o colaborador conhecia\n9. [ ] Revogar VPN ou acesso remoto\n10. [ ] Desativar cartão corporativo se aplicável\n\nIMPORTANTE: Para desligamentos involuntários (demissão), revogar acessos IMEDIATAMENTE após a conversa, ainda no Dia D.\n\n**5.5 Devolução de Equipamentos**\n1. Fazer checklist físico do equipamento devolvido (modelo, nº série, estado)\n2. Assinar Termo de Devolução\n3. Verificar se há arquivos pessoais do colaborador no equipamento e dar prazo de 24h para backup\n4. Limpar o equipamento (reset de fábrica / formatação) antes de redistribuir\n\n**5.6 Documentação Legal**\n\nPara CLT:\n- Homologação da rescisão (se necessário conforme tempo de empresa)\n- TRCT assinado\n- Guias de FGTS e seguro-desemprego (se aplicável)\n- Carta de demissão / Pedido de demissão\n- Prazo para pagamento: 10 dias após data de desligamento\n\nPara PJ:\n- Distrato assinado por ambas as partes\n- Nota fiscal final emitida\n- Declaração de encerramento de prestação de serviços\n\n**5.7 Entrevista de Saída**\n1. Head RH conduz, 30 min, após a confirmação da saída (não no último dia)\n2. Objetivo: coletar insights genuínos — não é momento de convencer a ficar\n3. Roteiro padrão:\n   - O que mais gostou de trabalhar na TBO?\n   - O que você mudaria nos processos?\n   - Há algo que impediu seu crescimento aqui?\n   - Como foi sua relação com a liderança?\n   - Você recomendaria a TBO como lugar para trabalhar? Por quê?\n4. Registrar respostas anonimizadas no TBO OS (módulo RH)\n5. Compilar insights trimestralmente para análise de padrões\n\n**5.8 Comunicação Interna**\n1. Ruy comunica para toda a equipe via Slack/reunião\n2. Tom: positivo, agradecendo contribuição (mesmo em demissões involuntárias — manter dignidade)\n3. Informar: último dia, quem absorve as responsabilidades, como a equipe pode ajudar na transição\n4. NÃO expor motivos do desligamento\n\n### 6. Checklist de Validação\n\n**Pessoas e Comunicação:**\n- [ ] Colaborador comunicado de forma direta e respeitosa\n- [ ] Equipe comunicada com tom adequado\n- [ ] Entrevista de saída realizada e registrada\n\n**Conhecimento:**\n- [ ] Projetos ativos passados para responsável\n- [ ] Documentações atualizadas no TBO OS\n- [ ] Credenciais compartilhadas atualizadas\n\n**Segurança (acessos):**\n- [ ] E-mail suspenso (não deletado) no Google Workspace\n- [ ] TBO OS revogado\n- [ ] Todas as ferramentas pagas revogadas\n- [ ] Redes sociais TBO/clientes revogadas\n- [ ] Senhas compartilhadas trocadas\n\n**Legal:**\n- [ ] TRCT assinado (CLT) ou Distrato assinado (PJ)\n- [ ] Equipamentos devolvidos com Termo de Devolução\n- [ ] Documentação arquivada no prontuário\n\n### 7. Ferramentas e Recursos\n\n- **Google Workspace Admin** — suspensão de contas\n- **TBO OS** — revogação de acesso e registro do offboarding\n- **Bitwarden** — gestão de credenciais compartilhadas\n- **Slack** — comunicação interna\n- Contador/DP — documentação trabalhista CLT\n- Template de Checklist de Offboarding (ver Template Anexo)\n- Template de Termo de Devolução de Equipamentos\n\n### 8. SLAs e Métricas\n\n| Etapa | SLA |\n|---|---|\n| Revogação de acessos (demissão involuntária) | Mesmo dia — imediatamente após conversa |\n| Revogação de acessos (pedido de demissão) | Último dia de trabalho |\n| Documentação legal CLT (TRCT) | Até 10 dias após desligamento |\n| Devolução de equipamentos | Até o último dia de trabalho |\n| Entrevista de saída | Dentro de 5 dias após comunicação |\n| Comunicação interna | Mesmo dia da comunicação ao colaborador |\n\n**KPIs:**\n- Zero incidentes de segurança pós-desligamento\n- 100% das entrevistas de saída registradas\n- 100% dos acessos revogados no prazo\n\n### 9. Troubleshooting\n\n**Colaborador recusa a entregar equipamento:**\n→ Acionar jurídico imediatamente\n→ Registrar recusa formal por escrito\n→ Não pagar verbas rescisórias até resolução (alinhar com advogado)\n\n**Colaborador tenta acessar sistemas após desligamento:**\n→ Verificar se os acessos foram corretamente revogados\n→ Registrar tentativas de acesso como incidente de segurança\n→ Acionar jurídico se houver dano ou suspeita de uso indevido de dados\n\n**Colaborador se recusa a fazer transferência de conhecimento:**\n→ Documentar recusa formalmente\n→ Head RH e Líder fazem mapeamento emergencial do que está em risco\n→ Se houver impacto em projetos de clientes: acionar Ruy para gestão de crise\n\n**Desligamento vazado para a equipe antes da comunicação oficial:**\n→ Antecipar comunicação interna para o mesmo dia\n→ Não confirmar nem negar boatos\n→ Comunicar com ainda mais cuidado e contexto\n\n### 10. Template Anexo\n\n```markdown\n# CHECKLIST DE OFFBOARDING — TBO\n\n**Colaborador:** ___________________________\n**Cargo/BU:** ___________________________\n**Tipo de desligamento:** [ ] Demissão sem justa causa [ ] Pedido de demissão [ ] Fim de contrato PJ [ ] Justa causa\n**Data da comunicação:** ___________________________\n**Último dia de trabalho:** ___________________________\n**Responsável RH:** ___________________________\n\n## FASE 1: PLANEJAMENTO\n- [ ] Tipo e data de desligamento definidos\n- [ ] Projetos ativos mapeados\n- [ ] Inventário de acessos levantado\n- [ ] Inventário de equipamentos levantado\n- [ ] Plano de transição de responsabilidades definido\n\n## FASE 2: COMUNICAÇÃO\n- [ ] Comunicação ao colaborador realizada (data: _______)\n- [ ] Entrevista de saída agendada para: _______\n- [ ] Comunicação interna à equipe realizada (data: _______)\n\n## FASE 3: TRANSIÇÃO DE CONHECIMENTO\n- [ ] Projetos passados para: ___________________________\n- [ ] Documentações atualizadas no TBO OS\n- [ ] Credenciais compartilhadas passadas via Bitwarden\n\n## FASE 4: REVOGAÇÃO DE ACESSOS\n- [ ] Google Workspace suspenso (não deletado)\n- [ ] TBO OS revogado\n- [ ] Slack removido\n- [ ] Figma revogado\n- [ ] Adobe CC revogado\n- [ ] Notion revogado\n- [ ] GitHub/repositórios revogados\n- [ ] Redes sociais TBO revogadas\n- [ ] Redes sociais de clientes revogadas\n- [ ] Senhas compartilhadas trocadas\n- [ ] VPN/acesso remoto revogado\n- [ ] Cartão corporativo cancelado [ ] N/A\n\n## FASE 5: EQUIPAMENTOS\n- [ ] Notebook devolvido — modelo: _______  s/n: _______  estado: _______\n- [ ] Periféricos devolvidos: ___________________________\n- [ ] Termo de Devolução assinado\n- [ ] Equipamento higienizado/formatado\n\n## FASE 6: DOCUMENTAÇÃO LEGAL\n- [ ] TRCT assinado / Distrato assinado\n- [ ] Carta de demissão / Pedido de demissão arquivado\n- [ ] Guias FGTS e Seguro-desemprego (se aplicável)\n- [ ] Prontuário arquivado\n\n## FASE 7: ENTREVISTA DE SAÍDA\n- [ ] Realizada em: _______\n- [ ] Insights registrados no TBO OS\n\n## Assinatura\n**Head RH:** ___________________________ Data: _______________\n**Ruy (Dir. Operações):** ___________________________ Data: _______________\n```',
    '',
    'published',
    'critical',
    ARRAY['offboarding', 'desligamento', 'RH', 'segurança', 'acessos', 'entrevista de saída', 'CLT', 'PJ', 'equipamentos'],
