  SELECT id INTO v_sop_id FROM knowledge_sops WHERE tenant_id = v_tenant_id AND slug = 'tbo-rh-010-offboarding-colaborador';

  INSERT INTO knowledge_sop_steps (sop_id, step_number, title, content, step_type, order_index)
  VALUES
    (v_sop_id, 1, 'Objetivo', 'Garantir que o desligamento de qualquer colaborador (CLT ou PJ) seja conduzido com organização, segurança e respeito — preservando o conhecimento institucional, protegendo ativos digitais, cumprindo obrigações legais e mantendo relação positiva com quem está saindo.', 'step', 0),
    (v_sop_id, 2, 'Escopo', 'Quem executa: Head de RH + Líder direto + Ruy (Dir. Operações). Aplica-se a desligamentos voluntários, involuntários e encerramento de contratos PJ. Não cobre justa causa com implicações jurídicas graves — nesses casos, envolver advogado trabalhista previamente.', 'step', 1),
    (v_sop_id, 3, 'RACI', E'| Atividade | Responsável | Aprovador | Consultado | Informado |\n|---|---|---|---|---|\n| Decisão de desligamento | Ruy/Marco | Marco/Ruy | Head RH | Líder direto |\n| Comunicação ao colaborador | Ruy | Marco | Head RH | Líder direto |\n| Documentação legal | Head RH | Ruy | Contador | Colaborador |\n| Revogação de acessos | Head RH | Ruy | Líder | — |\n| Transferência de conhecimento | Líder direto | Ruy | Colaborador | Equipe |\n| Entrevista de saída | Head RH | — | Ruy | — |\n| Comunicação interna | Ruy | Marco | Head RH | Toda equipe |', 'step', 2),
    (v_sop_id, 4, 'Pré-requisitos', E'- Decisão de desligamento formalizada e alinhada entre Marco e Ruy\n- Data de desligamento definida (respeitando aviso prévio CLT)\n- Inventário de acessos digitais do colaborador levantado\n- Inventário de equipamentos TBO em posse levantado\n- Projetos ativos e responsabilidades em curso mapeados', 'step', 3),
    (v_sop_id, 5, 'Procedimento', E'**D-30/Dia da decisão:** Planejamento — tipo de desligamento, data efetiva, plano de transição\n**Dia D:** Comunicação ao colaborador (direto, respeitoso, sem rodeios) → Registrar em ata interna\n**Período de transição:** Transferência de conhecimento estruturada → Documentação no TBO OS → Entrega de credenciais\n**Revogação de acessos** (último dia ou imediatamente para involuntários): Google Workspace → TBO OS → Slack → Ferramentas pagas → Redes sociais → Repositórios → Senhas compartilhadas\n**Devolução de equipamentos:** Checklist físico → Termo de Devolução → Reset de fábrica\n**Documentação legal:** TRCT (CLT) ou Distrato (PJ)\n**Entrevista de saída:** 30 min, Head RH, registrar no TBO OS\n**Comunicação interna:** Tom positivo, agradecer contribuição, informar transição', 'step', 4),
    (v_sop_id, 6, 'Checklist de Validação', E'**Comunicação:**\n- [ ] Colaborador comunicado de forma respeitosa\n- [ ] Equipe comunicada com tom adequado\n- [ ] Entrevista de saída realizada e registrada\n\n**Conhecimento:**\n- [ ] Projetos ativos passados para responsável\n- [ ] Documentações atualizadas no TBO OS\n- [ ] Credenciais compartilhadas atualizadas\n\n**Segurança:**\n- [ ] Google Workspace suspenso\n- [ ] TBO OS revogado\n- [ ] Todas ferramentas pagas revogadas\n- [ ] Senhas compartilhadas trocadas\n\n**Legal:**\n- [ ] TRCT/Distrato assinado\n- [ ] Equipamentos devolvidos com Termo\n- [ ] Documentação arquivada', 'checkpoint', 5),
    (v_sop_id, 7, 'Ferramentas e Recursos', E'- Google Workspace Admin (suspensão de contas)\n- TBO OS (revogação de acesso e registro)\n- Bitwarden (gestão de credenciais compartilhadas)\n- Slack (comunicação interna)\n- Contador/DP (documentação CLT)\n- Template Checklist de Offboarding (ver conteúdo completo)\n- Template Termo de Devolução de Equipamentos', 'tip', 6),
    (v_sop_id, 8, 'SLAs e Métricas', E'| Etapa | SLA |\n|---|---|\n| Revogação acessos (involuntário) | Imediatamente após conversa |\n| Revogação acessos (voluntário) | Último dia de trabalho |\n| TRCT/Distrato | Até 10 dias após desligamento |\n| Devolução de equipamentos | Até o último dia |\n| Entrevista de saída | Dentro de 5 dias |\n| Comunicação interna | Mesmo dia da comunicação |\n\n**KPIs:** Zero incidentes de segurança pós-desligamento · 100% das entrevistas registradas · 100% acessos revogados no prazo', 'note', 7),
    (v_sop_id, 9, 'Troubleshooting', E'**Recusa a entregar equipamento:** Acionar jurídico imediatamente. Registrar recusa formal. Alinhar verbas rescisórias com advogado.\n**Tentativa de acesso após desligamento:** Verificar revogação. Registrar como incidente de segurança. Acionar jurídico se houver dano.\n**Recusa a fazer transferência de conhecimento:** Documentar recusa. Head RH + Líder fazem mapeamento emergencial. Se impactar clientes: acionar Ruy para gestão de crise.\n**Vazamento antes da comunicação oficial:** Antecipar comunicação interna para o mesmo dia. Não confirmar/negar boatos.', 'warning', 8),
    (v_sop_id, 10, 'Template Anexo', E'**Checklist de Offboarding TBO** — Template copy-paste disponível no conteúdo completo deste SOP.\n\nFases cobertas: Planejamento · Comunicação · Transição de Conhecimento · Revogação de Acessos (lista completa de sistemas) · Equipamentos · Documentação Legal · Entrevista de Saída. Inclui campos de assinatura de RH e Direção.', 'tip', 9);

